mapper.select:
SELECT p.project_code, AS projectCode p.project_name, AS projectName SUM(CASE WHEN s.code_id = 'OB1' THEN 1 ELSE 0 END) AS newIss, SUM(CASE WHEN s.code_id = 'OB2' THEN 1 ELSE 0 END) AS progress, SUM(CASE WHEN s.code_id = 'OB3' THEN 1 ELSE 0 END) AS solution, SUM(CASE WHEN s.code_id = 'OB4' THEN 1 ELSE 0 END) AS returnIss, SUM(CASE WHEN s.code_id = 'OB5' THEN 1 ELSE 0 END) AS Completion FROM project_role_user pru JOIN projects p ON p.project_code = pru.project_code
LEFT JOIN issues i ON i.project_code = p.project_code
LEFT JOIN status s ON s.status_code = i.status_code WHERE pru.user_code = #{userCode}
GROUP BY p.project_code, p.project_name
ORDER BY p.project_code;
